/** FPSS control variant the SDK does not yet recognise. Surfaced when the core crate adds a new `FpssControl::*` arm — keep dispatch logic forward-compatible by handling this variant. Carries no payload. */
export interface UnknownControl {

}

/** FPSS server sent a frame with an unrecognised wire code. Mirrors `FpssControl::UnknownFrame`. Raw bytes preserved for diagnostics / upstream bug reports. */
export interface UnknownFrame {
  code: number
  payload: Array<number>
}

export declare const enum Venue {
  Nqb = 'nqb',
  UtpCta = 'utp_cta'
}

export declare const enum Version {
  Latest = 'latest',
  V1 = '1'
}

// ─────────────────────────────────────────────────────────────
// U7 closure: `Contract` is the documented public name for the
// fluent contract builder. napi-rs emits the class as
// `ContractRef` to avoid colliding with the FPSS event
// payload field; this alias keeps the documented name live.
// ─────────────────────────────────────────────────────────────
export const Contract: typeof ContractRef;
